            ctx.font = 'bold ' + (18 * ft.scale) + 'px PingFang SC';
            ctx.lineWidth = 2.5;
            ctx.strokeStyle = 'rgba(255,255,255,0.9)';
            ctx.strokeText(ft.text, ft.x, ft.y);
            ctx.fillStyle = ft.color;
            ctx.fillText(ft.text, ft.x, ft.y);
